package main

import (
	"html/template"
	"net/http"
	"os"
)

type Comment struct {
	User    string
	Message template.HTML
}

var comments = []Comment{
	{User: "Alice", Message: template.HTML("<b>Hello</b>, this is a <i>great</i> post!")},
	{User: "Bob", Message: template.HTML("I agree with <u>Alice</u>!")},
	{User: "Carol", Message: template.HTML("Nice work!<br>Keep it up.")},
}

var pageTmpl = template.Must(template.New("page").Parse(`
<!DOCTYPE html>
<html>
<head>
	<meta charset="utf-8">
	<title>User Comments</title>
	<style>
		body { font-family: sans-serif; margin: 2rem; }
		.comment { border-bottom: 1px solid #ddd; padding: 1rem 0; }
		.user { font-weight: bold; }
		.message { margin-top: 0.5rem; }
	</style>
</head>
<body>
	<h1>User Comments</h1>
	{{range .}}
	<div class="comment">
		<div class="user">{{.User}}</div>
		<div class="message">{{.Message}}</div>
	</div>
	{{else}}
	<p>No comments yet.</p>
	{{end}}
</body>
</html>
`))

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	_ = pageTmpl.Execute(w, comments)
}

func main() {
	http.HandleFunc("/", commentsHandler)
	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
	}
	_ = http.ListenAndServe(":"+port, nil)
}